import React from 'react';

function ResumePreview({ resume }) {

  return (

    <div
      className="container mt-4 mb-5"
      style={{
        maxWidth: '950px',
        background: '#ffffff',
        borderRadius: '20px',
        overflow: 'hidden',
        boxShadow: '0 0 25px rgba(0,0,0,0.1)'
      }}
    >

      {/* ================= HEADER ================= */}

      <div
        style={{
          background:
            'linear-gradient(135deg, #0f172a, #1e3a8a)',
          color: 'white',
          padding: '40px'
        }}
      >

        <div className="row align-items-center">

          <div className="col-md-8">

            <h1
              style={{
                fontSize: '42px',
                fontWeight: '700',
                marginBottom: '10px'
              }}
            >
              {resume.fullName}
            </h1>

            <h4
              style={{
                color: '#cbd5e1',
                marginBottom: '20px'
              }}
            >
              Java Full Stack Developer
            </h4>

            <p className="mb-1">
              📧 {resume.email}
            </p>

            <p className="mb-1">
              📱 {resume.phone}
            </p>

            <p className="mb-1">
              🔗 {resume.linkedin}
            </p>

            <p className="mb-1">
              💻 {resume.github}
            </p>

            <p className="mb-0">
              🌐 {resume.portfolio}
            </p>

          </div>

          <div className="col-md-4 text-center">

            <img
              src={resume.profileImage}
              alt="profile"
              style={{
                width: '180px',
                height: '180px',
                borderRadius: '50%',
                objectFit: 'cover',
                border: '6px solid white',
                boxShadow:
                  '0 0 15px rgba(255,255,255,0.4)'
              }}
            />

          </div>

        </div>

      </div>

      {/* ================= BODY ================= */}

      <div className="p-5">

        {/* SUMMARY */}

        <section className="mb-5">

          <h3
            style={{
              color: '#1e3a8a',
              borderBottom: '3px solid #1e3a8a',
              paddingBottom: '8px',
              marginBottom: '20px',
              fontWeight: '700'
            }}
          >
            Professional Summary
          </h3>

          <p
            style={{
              lineHeight: '1.9',
              color: '#444',
              fontSize: '16px',
              textAlign: 'justify'
            }}
          >
            {resume.summary}
          </p>

        </section>

        {/* SKILLS */}

        <section className="mb-5">

          <h3
            style={{
              color: '#1e3a8a',
              borderBottom: '3px solid #1e3a8a',
              paddingBottom: '8px',
              marginBottom: '20px',
              fontWeight: '700'
            }}
          >
            Skills
          </h3>

          <div className="row">

            <div className="col-md-6">

              <h5 className="fw-bold">
                Programming Languages
              </h5>

              <div className="d-flex flex-wrap gap-2">

                {
                  resume.programmingLanguages?.map(
                    (skill, index) => (

                      <span
                        key={index}
                        className="badge bg-primary p-2"
                      >
                        {skill}
                      </span>
                    )
                  )
                }

              </div>

            </div>

            <div className="col-md-6">

              <h5 className="fw-bold">
                Backend Technologies
              </h5>

              <div className="d-flex flex-wrap gap-2">

                {
                  resume.backendTechnologies?.map(
                    (skill, index) => (

                      <span
                        key={index}
                        className="badge bg-dark p-2"
                      >
                        {skill}
                      </span>
                    )
                  )
                }

              </div>

            </div>

          </div>

          <div className="row mt-4">

            <div className="col-md-6">

              <h5 className="fw-bold">
                Frontend Technologies
              </h5>

              <div className="d-flex flex-wrap gap-2">

                {
                  resume.frontendTechnologies?.map(
                    (skill, index) => (

                      <span
                        key={index}
                        className="badge bg-success p-2"
                      >
                        {skill}
                      </span>
                    )
                  )
                }

              </div>

            </div>

            <div className="col-md-6">

              <h5 className="fw-bold">
                Database
              </h5>

              <div className="d-flex flex-wrap gap-2">

                {
                  resume.database?.map(
                    (skill, index) => (

                      <span
                        key={index}
                        className="badge bg-warning text-dark p-2"
                      >
                        {skill}
                      </span>
                    )
                  )
                }

              </div>

            </div>

          </div>

          <div className="mt-4">

            <h5 className="fw-bold">
              Tools & Platforms
            </h5>

            <div className="d-flex flex-wrap gap-2">

              {
                resume.toolsPlatforms?.map(
                  (skill, index) => (

                    <span
                      key={index}
                      className="badge bg-secondary p-2"
                    >
                      {skill}
                    </span>
                  )
                )
              }

            </div>

          </div>

        </section>

        {/* EDUCATION */}

        <section className="mb-5">

          <h3
            style={{
              color: '#1e3a8a',
              borderBottom: '3px solid #1e3a8a',
              paddingBottom: '8px',
              marginBottom: '20px',
              fontWeight: '700'
            }}
          >
            Education
          </h3>

          <div
            style={{
              background: '#f8fafc',
              padding: '20px',
              borderRadius: '12px'
            }}
          >
            <p className="mb-0">
              {resume.education}
            </p>
          </div>

        </section>

        {/* EXPERIENCE */}

        <section className="mb-5">

          <h3
            style={{
              color: '#1e3a8a',
              borderBottom: '3px solid #1e3a8a',
              paddingBottom: '8px',
              marginBottom: '20px',
              fontWeight: '700'
            }}
          >
            Experience
          </h3>

          <div
            style={{
              background: '#f8fafc',
              padding: '20px',
              borderRadius: '12px'
            }}
          >
            <p className="mb-0">
              {resume.experience}
            </p>
          </div>

        </section>

        {/* PROJECTS */}

        <section className="mb-5">

          <h3
            style={{
              color: '#1e3a8a',
              borderBottom: '3px solid #1e3a8a',
              paddingBottom: '8px',
              marginBottom: '20px',
              fontWeight: '700'
            }}
          >
            Projects
          </h3>

          <div
            style={{
              background: '#f8fafc',
              padding: '20px',
              borderRadius: '12px'
            }}
          >
            <p className="mb-0">
              {resume.projects}
            </p>
          </div>

        </section>

        {/* LANGUAGES */}

        <section className="mb-5">

          <h3
            style={{
              color: '#1e3a8a',
              borderBottom: '3px solid #1e3a8a',
              paddingBottom: '8px',
              marginBottom: '20px',
              fontWeight: '700'
            }}
          >
            Languages
          </h3>

          <div className="d-flex gap-3 flex-wrap">

            {
              resume.languages?.map(
                (lang, index) => (

                  <span
                    key={index}
                    className="badge bg-info text-dark p-3"
                    style={{
                      fontSize: '14px'
                    }}
                  >
                    {lang}
                  </span>
                )
              )
            }

          </div>

        </section>

        {/* HOBBIES */}

        <section>

          <h3
            style={{
              color: '#1e3a8a',
              borderBottom: '3px solid #1e3a8a',
              paddingBottom: '8px',
              marginBottom: '20px',
              fontWeight: '700'
            }}
          >
            Hobbies
          </h3>

          <div className="d-flex gap-3 flex-wrap">

            {
              resume.hobbies?.map(
                (hobby, index) => (

                  <span
                    key={index}
                    className="badge bg-danger p-3"
                    style={{
                      fontSize: '14px'
                    }}
                  >
                    {hobby}
                  </span>
                )
              )
            }

          </div>

        </section>

      </div>

    </div>
  );
}

export default ResumePreview;
